namespace sv_c3ae3f05c8eb46188f8a21a93a38eb0b.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

public record ThemeInfo(Theme Theme, string AccentColor);

using Microsoft.AspNetCore.Components;

namespace sv_c3ae3f05c8eb46188f8a21a93a38eb0b.Services;

/// <summary>
/// Scoped service that owns the current theme state for a single circuit.
/// Components subscribe to <see cref="OnChange"/> for local re-renders.
/// Calling <see cref="SetThemeAsync"/> or <see cref="SetAccentColorAsync"/>
/// also pushes the new value through <see cref="CascadingValueSource{T}"/>
/// so that [CascadingParameter] subscribers (including static-rendered
/// components) update automatically.
/// </summary>
public class ThemeService
{
    private readonly CascadingValueSource<ThemeInfo> _source;

    public ThemeService(CascadingValueSource<ThemeInfo> source)
    {
        _source = source;
    }

    public Theme Theme { get; private set; } = Theme.Light;
    public string AccentColor { get; private set; } = "#0d6efd";

    public event Action? OnChange;

    public async Task SetThemeAsync(Theme theme)
    {
        Theme = theme;
        await NotifyAsync();
    }

    public async Task SetAccentColorAsync(string accentColor)
    {
        AccentColor = accentColor;
        await NotifyAsync();
    }

    public async Task SetAsync(Theme theme, string accentColor)
    {
        Theme = theme;
        AccentColor = accentColor;
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        var info = new ThemeInfo(Theme, AccentColor);
        await _source.NotifyChangedAsync(info);
        OnChange?.Invoke();
    }
}

