@inject ThemeService ThemeSvc
@implements IDisposable

<button class="btn btn-outline-secondary" @onclick="ToggleTheme">
    @(ThemeSvc.Theme == Theme.Dark ? "☀️ Light" : "🌙 Dark")
</button>

@code {
    protected override void OnInitialized()
    {
        ThemeSvc.OnChange += StateHasChanged;
    }

    private async Task ToggleTheme()
    {
        var next = ThemeSvc.Theme == Theme.Dark ? Theme.Light : Theme.Dark;
        await ThemeSvc.SetThemeAsync(next);
    }

    public void Dispose()
    {
        ThemeSvc.OnChange -= StateHasChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeService ThemeSvc
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label">Theme</label>
    <select class="form-select w-auto" value="@ThemeSvc.Theme"
            @onchange="OnThemeChanged">
        @foreach (var t in Enum.GetValues<Theme>())
        {
            <option value="@t">@t</option>
        }
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@ThemeSvc.AccentColor"
           @onchange="OnAccentChanged" />
</div>

<p>
    Current: <strong>@ThemeSvc.Theme</strong>,
    accent <span style="color:@ThemeSvc.AccentColor">●</span> @ThemeSvc.AccentColor
</p>

@code {
    protected override void OnInitialized()
    {
        ThemeSvc.OnChange += StateHasChanged;
    }

    private async Task OnThemeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<Theme>(e.Value?.ToString(), out var theme))
        {
            await ThemeSvc.SetThemeAsync(theme);
        }
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        var color = e.Value?.ToString();
        if (!string.IsNullOrEmpty(color))
        {
            await ThemeSvc.SetAccentColorAsync(color);
        }
    }

    public void Dispose()
    {
        ThemeSvc.OnChange -= StateHasChanged;
    }
}

